--
-- Name: enforce_operation_log_identity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enforce_operation_log_identity() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        INSERT INTO public.sys_operation_log_identity (id, log_no, event_id, operation_time)
        VALUES (NEW.id, NEW.log_no, NEW.event_id, NEW.operation_time);
        RETURN NEW;
    END IF;

    IF TG_OP = 'UPDATE' THEN
        IF OLD.id IS DISTINCT FROM NEW.id
                OR OLD.log_no IS DISTINCT FROM NEW.log_no
                OR OLD.event_id IS DISTINCT FROM NEW.event_id
                OR OLD.operation_time IS DISTINCT FROM NEW.operation_time THEN
            UPDATE public.sys_operation_log_identity
               SET id = NEW.id,
                   log_no = NEW.log_no,
                   event_id = NEW.event_id,
                   operation_time = NEW.operation_time
             WHERE id = OLD.id;
        END IF;
        RETURN NEW;
    END IF;

    DELETE FROM public.sys_operation_log_identity WHERE id = OLD.id;
    RETURN OLD;
END
$$;


SET default_tablespace = '';

SET default_table_access_method = heap;

--
-- Name: auth_refresh_token; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.auth_refresh_token (
    id bigint NOT NULL,
    user_id bigint NOT NULL,
    token_id character varying(36) NOT NULL,
    token_hash character varying(128) NOT NULL,
    expires_at timestamp without time zone NOT NULL,
    revoked_at timestamp without time zone,
    login_ip character varying(64),
    device_info character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    revoke_reason character varying(32),
    previous_token_hash character varying(128),
    previous_token_valid_until timestamp without time zone,
    credential_version bigint DEFAULT 0 NOT NULL,
    CONSTRAINT chk_refresh_token_revoke_reason CHECK (((revoke_reason IS NULL) OR ((revoke_reason)::text = ANY ((ARRAY['MANUAL'::character varying, 'CONCURRENT_LIMIT'::character varying, 'EXPIRED'::character varying, 'REUSE_DETECTED'::character varying, 'PASSWORD_CHANGED'::character varying])::text[]))))
);


--
-- Name: COLUMN auth_refresh_token.revoke_reason; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.auth_refresh_token.revoke_reason IS '撤销原因: MANUAL/CONCURRENT_LIMIT/EXPIRED/REUSE_DETECTED/PASSWORD_CHANGED';


--
-- Name: COLUMN auth_refresh_token.credential_version; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.auth_refresh_token.credential_version IS '刷新会话签发时的用户凭据版本';


