--
-- Name: fm_ledger_adjustment; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.fm_ledger_adjustment (
    id bigint NOT NULL,
    version bigint,
    adjustment_no character varying(64) NOT NULL,
    direction character varying(16) NOT NULL,
    counterparty_type character varying(32) NOT NULL,
    counterparty_code character varying(64) NOT NULL,
    counterparty_name character varying(128) NOT NULL,
    project_id bigint,
    project_name character varying(200),
    adjustment_date date NOT NULL,
    amount numeric(14,2) NOT NULL,
    adjustment_type character varying(32) NOT NULL,
    effect character varying(32) NOT NULL,
    status character varying(16) NOT NULL,
    operator_name character varying(32) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    settlement_company_id bigint,
    settlement_company_name character varying(128),
    counterparty_id bigint NOT NULL,
    CONSTRAINT chk_fm_ledger_adjustment_settlement_company_pair CHECK ((((settlement_company_id IS NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NULL)) OR ((settlement_company_id IS NOT NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NOT NULL)))),
    CONSTRAINT chk_fm_ledger_adjustment_typed_party_project CHECK ((((counterparty_type)::text = ANY ((ARRAY['客户'::character varying, '供应商'::character varying, '物流商'::character varying])::text[])) AND (counterparty_id IS NOT NULL) AND (((counterparty_type)::text = '客户'::text) OR (((counterparty_type)::text = ANY ((ARRAY['供应商'::character varying, '物流商'::character varying])::text[])) AND (project_id IS NULL) AND (NULLIF(btrim((project_name)::text), ''::text) IS NULL))))),
    CONSTRAINT chk_ledger_adjustment_amount CHECK ((amount > (0)::numeric)),
    CONSTRAINT chk_ledger_adjustment_counterparty_type CHECK (((counterparty_type)::text = ANY (ARRAY[('客户'::character varying)::text, ('供应商'::character varying)::text, ('物流商'::character varying)::text]))),
    CONSTRAINT chk_ledger_adjustment_direction CHECK (((direction)::text = ANY (ARRAY[('应收'::character varying)::text, ('应付'::character varying)::text]))),
    CONSTRAINT chk_ledger_adjustment_effect CHECK (((effect)::text = ANY (ARRAY[('增加余额'::character varying)::text, ('减少余额'::character varying)::text]))),
    CONSTRAINT chk_ledger_adjustment_status CHECK (((status)::text = ANY (ARRAY[('草稿'::character varying)::text, ('已审核'::character varying)::text]))),
    CONSTRAINT chk_ledger_adjustment_type CHECK (((adjustment_type)::text = ANY (ARRAY[('坏账'::character varying)::text, ('抹零'::character varying)::text, ('折让'::character varying)::text, ('其他调整'::character varying)::text])))
);


