--
-- Name: fm_payment; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.fm_payment (
    id bigint NOT NULL,
    payment_no character varying(64) NOT NULL,
    business_type character varying(32) NOT NULL,
    counterparty_name character varying(128) NOT NULL,
    payment_date timestamp without time zone NOT NULL,
    pay_type character varying(32) NOT NULL,
    amount numeric(14,2) NOT NULL,
    status character varying(16) NOT NULL,
    operator_name character varying(32) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    source_statement_id bigint,
    version bigint DEFAULT 0 NOT NULL,
    counterparty_code character varying(64),
    payment_purpose character varying(32) DEFAULT 'STATEMENT_SETTLEMENT'::character varying NOT NULL,
    source_purchase_order_id bigint,
    purchase_order_no character varying(64),
    supplier_code character varying(64),
    supplier_name character varying(128),
    settlement_company_id bigint,
    settlement_company_name character varying(128),
    counterparty_type character varying(32) NOT NULL,
    counterparty_id bigint NOT NULL,
    CONSTRAINT chk_fm_payment_amount_positive CHECK ((amount > (0)::numeric)),
    CONSTRAINT chk_fm_payment_purchase_prepayment CHECK ((((payment_purpose)::text <> 'PURCHASE_PREPAYMENT'::text) OR (((business_type)::text = '供应商'::text) AND (source_statement_id IS NULL) AND (source_purchase_order_id IS NOT NULL) AND (NULLIF(btrim((purchase_order_no)::text), ''::text) IS NOT NULL) AND (NULLIF(btrim((supplier_code)::text), ''::text) IS NOT NULL) AND (NULLIF(btrim((supplier_name)::text), ''::text) IS NOT NULL) AND (settlement_company_id IS NOT NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NOT NULL) AND (amount > (0)::numeric)))),
    CONSTRAINT chk_fm_payment_purpose CHECK (((payment_purpose)::text = ANY ((ARRAY['STATEMENT_SETTLEMENT'::character varying, 'PURCHASE_PREPAYMENT'::character varying, 'SUPPLIER_PAYMENT'::character varying])::text[]))),
    CONSTRAINT chk_fm_payment_settlement_company_pair CHECK ((((settlement_company_id IS NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NULL)) OR ((settlement_company_id IS NOT NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NOT NULL)))),
    CONSTRAINT chk_fm_payment_statement_settlement CHECK ((((payment_purpose)::text <> 'STATEMENT_SETTLEMENT'::text) OR (source_purchase_order_id IS NULL))),
    CONSTRAINT chk_fm_payment_supplier_total_v58 CHECK (((((payment_purpose)::text = 'SUPPLIER_PAYMENT'::text) AND ((business_type)::text = '供应商'::text) AND ((counterparty_type)::text = '供应商'::text) AND (counterparty_id IS NOT NULL) AND (NULLIF(btrim((counterparty_name)::text), ''::text) IS NOT NULL) AND (settlement_company_id IS NOT NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NOT NULL) AND (amount > (0)::numeric) AND (source_statement_id IS NULL) AND (source_purchase_order_id IS NULL) AND (purchase_order_no IS NULL)) OR ((payment_purpose)::text = ANY ((ARRAY['STATEMENT_SETTLEMENT'::character varying, 'PURCHASE_PREPAYMENT'::character varying])::text[])))),
    CONSTRAINT chk_fm_payment_typed_counterparty CHECK ((((counterparty_type)::text = ANY ((ARRAY['供应商'::character varying, '物流商'::character varying])::text[])) AND (counterparty_id IS NOT NULL) AND ((counterparty_type)::text = (business_type)::text))),
    CONSTRAINT chk_fm_payment_version_nonnegative CHECK ((version >= 0)),
    CONSTRAINT chk_payment_status CHECK (((status)::text = ANY ((ARRAY['草稿'::character varying, '已审核'::character varying])::text[])))
)
WITH (fillfactor='70');


