-- Name: fm_receipt; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.fm_receipt (
    id bigint NOT NULL,
    receipt_no character varying(64) NOT NULL,
    customer_name character varying(128),
    project_name character varying(200),
    receipt_date timestamp without time zone NOT NULL,
    pay_type character varying(32) NOT NULL,
    amount numeric(14,2) NOT NULL,
    status character varying(16) NOT NULL,
    operator_name character varying(32) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    source_customer_statement_id bigint,
    version bigint,
    customer_code character varying(64),
    project_id bigint,
    settlement_company_id bigint,
    settlement_company_name character varying(128),
    customer_id bigint,
    counterparty_type character varying(32) NOT NULL,
    counterparty_id bigint NOT NULL,
    counterparty_code character varying(64),
    counterparty_name character varying(128) NOT NULL,
    receipt_purpose character varying(32) NOT NULL,
    CONSTRAINT chk_fm_receipt_counterparty_type_v58 CHECK (((counterparty_type)::text = ANY ((ARRAY['客户'::character varying, '供应商'::character varying])::text[]))),
    CONSTRAINT chk_fm_receipt_ledger_shape_v58 CHECK (((amount > (0)::numeric) AND (NULLIF(btrim((counterparty_name)::text), ''::text) IS NOT NULL) AND (((counterparty_type)::text = '客户'::text) OR (((counterparty_type)::text = '供应商'::text) AND (settlement_company_id IS NOT NULL) AND (NULLIF(btrim((settlement_company_name)::text), ''::text) IS NOT NULL))))),
    CONSTRAINT chk_fm_receipt_party_shape_v58 CHECK (((((counterparty_type)::text = '客户'::text) AND ((receipt_purpose)::text = 'CUSTOMER_STATEMENT_SETTLEMENT'::text) AND (customer_id IS NOT NULL) AND (counterparty_id = customer_id) AND (project_id IS NOT NULL)) OR (((counterparty_type)::text = '供应商'::text) AND ((receipt_purpose)::text = ANY ((ARRAY['SUPPLIER_PREPAYMENT_REFUND'::character varying, 'SUPPLIER_OTHER_RECEIPT'::character varying])::text[])) AND (customer_id IS NULL) AND (project_id IS NULL) AND (source_customer_statement_id IS NULL)))),
    CONSTRAINT chk_fm_receipt_purpose_v58 CHECK (((receipt_purpose)::text = ANY ((ARRAY['CUSTOMER_STATEMENT_SETTLEMENT'::character varying, 'SUPPLIER_PREPAYMENT_REFUND'::character varying, 'SUPPLIER_OTHER_RECEIPT'::character varying])::text[]))),
    CONSTRAINT chk_receipt_status CHECK (((status)::text = ANY ((ARRAY['草稿'::character varying, '已审核'::character varying])::text[])))
)
WITH (fillfactor='70');


