   FROM (public.st_customer_statement customer_statement
     LEFT JOIN customer_statement_sources ON ((customer_statement_sources.record_id = customer_statement.id)))
UNION ALL
 SELECT 'freight-statement'::text AS module_key,
    freight_statement.id AS record_id,
    (freight_statement.statement_no)::text AS primary_no,
    concat_ws(' / '::text, NULLIF(btrim((freight_statement.carrier_name)::text), ''::text), NULLIF(btrim((freight_statement.sign_status)::text), ''::text), NULLIF(btrim((freight_statement.status)::text), ''::text)) AS summary,
    concat_ws(' '::text, (freight_statement.id)::text, freight_statement.statement_no, freight_statement_sources.source_nos, freight_statement.carrier_code, freight_statement.carrier_name, freight_statement.sign_status, freight_statement.status, freight_statement.remark) AS search_text,
