    material_code character varying(64) NOT NULL,
    brand character varying(64) NOT NULL,
    category character varying(16) NOT NULL,
    material character varying(16) NOT NULL,
    spec character varying(64) NOT NULL,
    length character varying(32),
    unit character varying(8) NOT NULL,
    batch_no character varying(64),
    quantity integer NOT NULL,
    piece_weight_ton numeric(18,8) NOT NULL,
    pieces_per_bundle integer NOT NULL,
    weight_ton numeric(18,8) NOT NULL,
    unit_price numeric(12,2) NOT NULL,
    amount numeric(14,2) NOT NULL,
    quantity_unit character varying(8) DEFAULT '件'::character varying NOT NULL,
    warehouse_name character varying(128),
    source_purchase_order_item_id bigint NOT NULL,
    weigh_weight_ton numeric(18,8),
    weight_adjustment_ton numeric(18,8) DEFAULT 0 NOT NULL,
    weight_adjustment_amount numeric(14,2) DEFAULT 0 NOT NULL,
    settlement_mode character varying(32) NOT NULL,
    settlement_company_id bigint,
    settlement_company_name character varying(128),
    material_id bigint NOT NULL,
    warehouse_id bigint NOT NULL,
    batch_no_normalized character varying(64) GENERATED ALWAYS AS (NULLIF(btrim((batch_no)::text), ''::text)) STORED,
    tolerance_direction character varying(8),
    tolerance_limit_percent numeric(8,4),
    tolerance_actual_percent numeric(24,4),
    tolerance_reason_code character varying(64),
    tolerance_remark character varying(255),
    tolerance_confirmed_by bigint,
    tolerance_confirmed_name character varying(64),
    tolerance_confirmed_at timestamp without time zone,
    CONSTRAINT chk_purchase_inbound_tolerance_confirmation_complete CHECK ((((tolerance_reason_code IS NULL) AND (tolerance_direction IS NULL) AND (tolerance_limit_percent IS NULL) AND (tolerance_actual_percent IS NULL) AND (tolerance_remark IS NULL) AND (tolerance_confirmed_by IS NULL) AND (tolerance_confirmed_name IS NULL) AND (tolerance_confirmed_at IS NULL)) OR ((tolerance_reason_code IS NOT NULL) AND (tolerance_direction IS NOT NULL) AND (tolerance_limit_percent IS NOT NULL) AND (tolerance_actual_percent IS NOT NULL) AND (tolerance_confirmed_by IS NOT NULL) AND (tolerance_confirmed_by >= 0) AND (NULLIF(btrim((tolerance_confirmed_name)::text), ''::text) IS NOT NULL) AND (tolerance_confirmed_at IS NOT NULL)))),
    CONSTRAINT chk_purchase_inbound_tolerance_direction CHECK (((tolerance_direction IS NULL) OR ((tolerance_direction)::text = ANY ((ARRAY['上差'::character varying, '下差'::character varying])::text[])))),
    CONSTRAINT chk_purchase_inbound_tolerance_other_remark CHECK ((((tolerance_reason_code)::text <> 'OTHER'::text) OR (NULLIF(btrim((tolerance_remark)::text), ''::text) IS NOT NULL))),
    CONSTRAINT chk_purchase_inbound_tolerance_percent CHECK ((((tolerance_limit_percent IS NULL) OR ((tolerance_limit_percent >= (0)::numeric) AND (tolerance_limit_percent <= (100)::numeric))) AND ((tolerance_actual_percent IS NULL) OR (tolerance_actual_percent >= (0)::numeric)))),
    CONSTRAINT chk_purchase_inbound_tolerance_reason CHECK (((tolerance_reason_code IS NULL) OR ((tolerance_reason_code)::text = ANY ((ARRAY['TRANSPORT_LOSS'::character varying, 'HANDLING_LOSS'::character varying, 'MEASUREMENT_DIFFERENCE'::character varying, 'SUPPLIER_CONFIRMED'::character varying, 'MOISTURE_OR_IMPURITY_CHANGE'::character varying, 'THEORETICAL_WEIGHT_DEVIATION'::character varying, 'OTHER'::character varying])::text[]))))
);


