    weight_ton numeric(18,8) NOT NULL,
    unit_price numeric(12,2) NOT NULL,
    amount numeric(14,2) NOT NULL,
    material_id bigint NOT NULL,
    warehouse_id bigint,
    batch_no_normalized character varying(64) GENERATED ALWAYS AS (NULLIF(btrim((batch_no)::text), ''::text)) STORED,
    CONSTRAINT chk_po_purchase_refund_item_line_positive CHECK ((line_no > 0)),
    CONSTRAINT chk_po_purchase_refund_item_values_nonnegative CHECK (((quantity >= 0) AND (piece_weight_ton >= (0)::numeric) AND (pieces_per_bundle >= 0) AND (weight_ton >= (0)::numeric) AND (unit_price >= (0)::numeric) AND (amount >= (0)::numeric)))
);


