--
-- Name: sys_print_template; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sys_print_template (
    id bigint NOT NULL,
    bill_type character varying(64) NOT NULL,
    template_name character varying(128) NOT NULL,
    template_html text NOT NULL,
    is_default boolean DEFAULT false NOT NULL,
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    template_type character varying(16) DEFAULT 'HTML'::character varying NOT NULL,
    template_code character varying(96) NOT NULL,
    engine character varying(32) NOT NULL,
    asset_ref character varying(255),
    version_no integer DEFAULT 1 NOT NULL,
    status character varying(16) DEFAULT 'ACTIVE'::character varying NOT NULL,
    sync_mode character varying(16) DEFAULT 'MANUAL'::character varying NOT NULL,
    source_ref character varying(255),
    source_checksum character varying(64),
    settlement_company_id bigint,
    settlement_company_name character varying(128),
    CONSTRAINT chk_print_template_engine CHECK (((engine)::text = ANY (ARRAY[('LODOP'::character varying)::text, ('PDF_FORM'::character varying)::text]))),
    CONSTRAINT chk_print_template_file_source CHECK (((((sync_mode)::text = 'FILE'::text) AND (source_ref IS NOT NULL) AND (btrim((source_ref)::text) <> ''::text)) OR ((sync_mode)::text = 'MANUAL'::text))),
    CONSTRAINT chk_print_template_pdf_asset CHECK (((((template_type)::text = 'PDF_FORM'::text) AND ((asset_ref IS NULL) OR (btrim((asset_ref)::text) = ''::text) OR (lower((asset_ref)::text) ~~ '%.pdf'::text))) OR (((template_type)::text <> 'PDF_FORM'::text) AND (asset_ref IS NULL)))),
    CONSTRAINT chk_print_template_status CHECK (((status)::text = ANY (ARRAY[('ACTIVE'::character varying)::text, ('DISABLED'::character varying)::text]))),
    CONSTRAINT chk_print_template_sync_mode CHECK (((sync_mode)::text = ANY (ARRAY[('MANUAL'::character varying)::text, ('FILE'::character varying)::text]))),
    CONSTRAINT chk_print_template_type CHECK (((template_type)::text = ANY (ARRAY[('COORD'::character varying)::text, ('PDF_FORM'::character varying)::text]))),
    CONSTRAINT chk_print_template_type_engine CHECK (((((template_type)::text = 'COORD'::text) AND ((engine)::text = 'LODOP'::text)) OR (((template_type)::text = 'PDF_FORM'::text) AND ((engine)::text = 'PDF_FORM'::text)))),
    CONSTRAINT chk_print_template_version_no CHECK ((version_no >= 1))
);


--
-- Name: sys_security_secret; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sys_security_secret (
    id bigint NOT NULL,
    secret_type character varying(32) NOT NULL,
    secret_name character varying(64) NOT NULL,
    key_version integer NOT NULL,
    secret_value text NOT NULL,
    status character varying(16) DEFAULT 'ACTIVE'::character varying NOT NULL,
    activated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    retired_at timestamp without time zone,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    CONSTRAINT chk_security_secret_status CHECK (((status)::text = ANY (ARRAY[('ACTIVE'::character varying)::text, ('RETIRED'::character varying)::text])))
);


--
-- Name: sys_user; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sys_user (
    id bigint NOT NULL,
    login_name character varying(64) NOT NULL,
    password_hash character varying(128) NOT NULL,
    user_name character varying(64) NOT NULL,
    mobile character varying(20),
    last_login_date timestamp without time zone,
    status character varying(16) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    department_id bigint,
    department_name character varying(128),
    version bigint,
    preferences_json jsonb,
    credential_version bigint DEFAULT 0 NOT NULL,
    CONSTRAINT chk_sys_user_status CHECK (((status)::text = ANY (ARRAY[('NORMAL'::character varying)::text, ('DISABLED'::character varying)::text])))
)
WITH (fillfactor='80');


